import { Injectable, UnauthorizedException } from '@nestjs/common';
import { UsersService } from '../users/users.service';
import { TenantsService } from '../tenants/tenants.service';
import { JwtService } from '@nestjs/jwt';
import * as bcrypt from 'bcrypt';

@Injectable()
export class AuthService {
  constructor(
    private usersService: UsersService,
    private tenantsService: TenantsService,
    private jwtService: JwtService,
  ) {}

  async validateUser(email: string, pass: string): Promise<any> {
    const user = await this.usersService.findByEmail(email);
    if (user && (await bcrypt.compare(pass, user.passwordHash))) {
      if (user.tenant && user.tenant.isActive === false) {
        throw new UnauthorizedException(
          'Lo sentimos, su cuenta ha sido suspendida. Contacte al administrador',
        );
      }
      const { passwordHash, ...result } = user;
      return result;
    }
    return null;
  }

  async login(user: any) {
    const payload = {
      email: user.email,
      sub: user.id,
      tenantId: user.tenantId,
      role: user.role,
      name: user.name,
    };
    return {
      access_token: this.jwtService.sign(payload),
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
        role: user.role,
        tenant_modules:
          user.tenant?.modules && user.tenant.modules.length > 0
            ? user.tenant.modules
            : [
                'POS',
                'CLOSURE',
                'INVENTORY',
                'REPORTS',
                'SUPPLIERS',
                'CUSTOMERS',
                'CREDITS',
                'REFUNDS',
                'ACCOUNTING',
              ],
      },
    };
  }

  async register(registerDto: Record<string, any>) {
    const existing = await this.usersService.findByEmail(registerDto.email);
    if (existing) {
      throw new Error('El correo electrónico ya está registrado');
    }
    // 1. Create Tenant
    const tenant = await this.tenantsService.create(
      registerDto.storeName,
      registerDto.modules,
    );

    // 2. Hash Password
    const saltRounds = 10;
    const passwordHash = await bcrypt.hash(registerDto.password, saltRounds);

    // 3. Create User linked to Tenant
    const user = await this.usersService.create({
      tenantId: tenant.id,
      name: registerDto.userName,
      email: registerDto.email,
      passwordHash,
      role: 'OWNER',
    });

    // 4. Return Login Token
    return this.login(user);
  }
}

import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { Role } from '../enums/role.enum';
import { ROLES_KEY } from '../decorators/roles.decorator';

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const { user } = context.switchToHttp().getRequest();

    // El SUPER_ADMIN tiene acceso total a todos los recursos protegidos por roles
    if (user && user.role === Role.SUPER_ADMIN) {
      return true;
    }

    const requiredRoles = this.reflector.getAllAndOverride<Role[]>(ROLES_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (!requiredRoles) {
      return true;
    }

    return requiredRoles.some((role) => user.role === role);
  }
}

import { ExtractJwt, Strategy } from 'passport-jwt';
import { PassportStrategy } from '@nestjs/passport';
import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class JwtStrategy extends PassportStrategy(Strategy) {
  constructor(private configService: ConfigService) {
    super({
      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
      ignoreExpiration: false,
      secretOrKey: configService.get<string>(
        'JWT_SECRET',
        'super-secret-tiendeo-key-123',
      ),
    });
  }

  async validate(payload: any) {
    return {
      userId: payload.sub,
      email: payload.email,
      tenantId: payload.tenantId,
      role: payload.role,
      name: payload.name,
    };
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { Cron, CronExpression } from '@nestjs/schedule';
import * as Minio from 'minio';
import { exec } from 'child_process';
import { promisify } from 'util';
import * as fs from 'fs';
import * as path from 'path';

const execPromise = promisify(exec);

@Injectable()
export class BackupsService {
  private readonly logger = new Logger(BackupsService.name);
  private minioClient: Minio.Client;
  private readonly bucketName = 'database-backups';

  constructor(private configService: ConfigService) {
    this.minioClient = new Minio.Client({
      endPoint: this.configService.get('MINIO_ENDPOINT', 'minio'),
      port: parseInt(this.configService.get('MINIO_PORT', '9000')),
      useSSL: false,
      accessKey: this.configService.get('MINIO_ACCESS_KEY', 'minioadmin'),
      secretKey: this.configService.get('MINIO_SECRET_KEY', 'minioadmin123'),
    });
    this.ensureBucketExists();
  }

  private async ensureBucketExists() {
    try {
      const exists = await this.minioClient.bucketExists(this.bucketName);
      if (!exists) {
        await this.minioClient.makeBucket(this.bucketName);
        this.logger.log(`Bucket ${this.bucketName} created.`);
      }
    } catch (error) {
      this.logger.error('Error ensuring bucket exists:', error);
    }
  }

  @Cron(CronExpression.EVERY_DAY_AT_MIDNIGHT)
  async handleCron() {
    this.logger.log('Starting scheduled daily backup...');
    await this.createBackup();
  }

  async createBackup(): Promise<string> {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const fileName = `backup-${timestamp}.sql`;
    const tempPath = path.join('/tmp', fileName);

    const dbUser = this.configService.get('DB_USER', 'postgres');
    const dbPass = this.configService.get('DB_PASSWORD', 'password123');
    const dbHost = this.configService.get('DB_HOST', 'db');
    const dbName = this.configService.get('DB_NAME', 'tiendeo');

    try {
      this.logger.log(`Generating dump: ${fileName}`);
      // PGPASSWORD is used to avoid interactive prompt
      await execPromise(
        `PGPASSWORD="${dbPass}" pg_dump -h ${dbHost} -U ${dbUser} -d ${dbName} -f ${tempPath}`,
      );

      this.logger.log(`Uploading to Minio: ${fileName}`);
      await this.minioClient.fPutObject(this.bucketName, fileName, tempPath);

      // Clean up temp file
      if (fs.existsSync(tempPath)) {
        fs.unlinkSync(tempPath);
      }

      this.logger.log('Backup completed successfully.');
      return fileName;
    } catch (error) {
      this.logger.error('Backup failed:', error);
      throw error;
    }
  }

  async listBackups() {
    return new Promise((resolve, reject) => {
      const backups: any[] = [];
      const stream = this.minioClient.listObjectsV2(this.bucketName, '', true);
      stream.on('data', (obj) => backups.push(obj));
      stream.on('error', (err) => reject(err));
      stream.on('end', () =>
        resolve(
          backups.sort(
            (a, b) => b.lastModified.getTime() - a.lastModified.getTime(),
          ),
        ),
      );
    });
  }

  async getDownloadUrl(fileName: string): Promise<string> {
    return await this.minioClient.presignedGetObject(
      this.bucketName,
      fileName,
      24 * 60 * 60,
    ); // 24h
  }

  async deleteBackup(fileName: string): Promise<void> {
    await this.minioClient.removeObject(this.bucketName, fileName);
  }
}

import {
  Controller,
  Get,
  Post,
  Body,
  Patch,
  Param,
  Delete,
  UseGuards,
  Request,
} from '@nestjs/common';
import { CategoriesService } from './categories.service';
import { JwtAuthGuard } from '../auth/jwt-auth.guard';
import { RolesGuard } from '../auth/guards/roles.guard';
import { Roles } from '../auth/decorators/roles.decorator';
import { Role } from '../auth/enums/role.enum';

@Controller('categories')
@UseGuards(JwtAuthGuard, RolesGuard)
export class CategoriesController {
  constructor(private readonly categoriesService: CategoriesService) {}

  @Post()
  @Roles(Role.ADMIN, Role.OWNER)
  create(@Body() createCategoryDto: any, @Request() req: any) {
    return this.categoriesService.create(createCategoryDto, req.user.tenantId);
  }

  @Get()
  @Roles(Role.ADMIN, Role.OWNER, Role.CASHIER)
  findAll(@Request() req: any) {
    return this.categoriesService.findAll(req.user.tenantId);
  }

  @Get(':id')
  findOne(@Param('id') id: string, @Request() req: any) {
    return this.categoriesService.findOne(id, req.user.tenantId);
  }

  @Patch(':id')
  @Roles(Role.ADMIN, Role.OWNER)
  update(
    @Param('id') id: string,
    @Body() updateCategoryDto: any,
    @Request() req: any,
  ) {
    return this.categoriesService.update(
      id,
      updateCategoryDto,
      req.user.tenantId,
    );
  }

  @Delete(':id')
  @Roles(Role.ADMIN, Role.OWNER)
  remove(@Param('id') id: string, @Request() req: any) {
    return this.categoriesService.remove(id, req.user.tenantId);
  }
