import { Injectable, NotFoundException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { Customer } from './entities/customer.entity';
import { CreditSale } from '../sales/entities/credit-sale.entity';
import { SalesService } from '../sales/sales.service';

@Injectable()
export class CustomersService {
  constructor(
    @InjectRepository(Customer)
    private customersRepository: Repository<Customer>,
    @InjectRepository(CreditSale)
    private creditSalesRepository: Repository<CreditSale>,
    private salesService: SalesService,
  ) {}

  async create(tenantId: string, userId: string, userName: string, data: any) {
    const { initialDebt, ...customerData } = data;
    const customer = this.customersRepository.create({
      ...customerData,
      tenantId,
    });
    const savedCustomer = await (this.customersRepository.save(
      customer,
    ) as any);

    if (initialDebt && initialDebt > 0) {
      await this.salesService.createLegacyDebt(
        tenantId,
        userId,
        userName,
        savedCustomer.id,
        initialDebt,
      );
    }

    return savedCustomer;
  }

  async findAll(tenantId: string, full = false) {
    const customers = await this.customersRepository.find({
      where: { tenantId },
      relations: full
        ? ['creditSales', 'creditSales.sale', 'creditSales.payments']
        : ['creditSales'],
      order: { name: 'ASC' },
    });

    return customers.map((c) => {
      const totalDebt = c.creditSales
        .filter((cs) => cs.status !== 'PAID')
        .reduce((sum, cs) => sum + Number(cs.remainingAmount), 0);
      const pendingInvoices = c.creditSales.filter(
        (cs) => cs.status !== 'PAID',
      ).length;

      // Remove creditSales from output to keep it light if not requested full
      if (!full) {
        delete (c as any).creditSales;
      }

      return {
        ...c,
        totalDebt,
        pendingInvoices,
      };
    });
  }

  async findOne(tenantId: string, id: string) {
    const customer = await this.customersRepository.findOne({
      where: { id, tenantId },
      relations: ['creditSales', 'creditSales.sale', 'creditSales.payments'],
      order: {
        creditSales: {
          createdAt: 'DESC',
        },
      },
    });
    if (!customer) throw new NotFoundException('Customer not found');
    return customer;
  }

  async update(
    tenantId: string,
    userId: string,
    userName: string,
    id: string,
    data: any,
  ) {
    const { initialDebt, ...customerData } = data;
    await this.findOne(tenantId, id);
    await this.customersRepository.update(id, customerData);

    if (initialDebt && initialDebt > 0) {
      await this.salesService.createLegacyDebt(
        tenantId,
        userId,
        userName,
        id,
        initialDebt,
      );
    }

    return this.findOne(tenantId, id);
  }

  async remove(tenantId: string, id: string) {
    const customer = await this.findOne(tenantId, id);

    // Eliminar relaciones manualmente para asegurar que el botón de la UI funcione siempre
    await this.creditSalesRepository.delete({ customerId: id });

    return this.customersRepository.remove(customer);
  }
}

import {
  Entity,
  PrimaryGeneratedColumn,
  Column,
  CreateDateColumn,
  UpdateDateColumn,
  OneToMany,
} from 'typeorm';
import { CreditSale } from '../../sales/entities/credit-sale.entity';

@Entity('customers')
export class Customer {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column({ name: 'local_id', nullable: true })
  localId: string;

  @Column({ name: 'tenant_id' })
  tenantId: string;

  @Column()
  name: string;

  @Column({ name: 'id_number', nullable: true })
  idNumber: string;

  @Column({ nullable: true })
  phone: string;

  @Column({ nullable: true })
  email: string;

  @Column({ nullable: true, type: 'text' })
  address: string;

  @OneToMany(() => CreditSale, (creditSale) => creditSale.customer)
  creditSales: CreditSale[];

  @CreateDateColumn({ name: 'created_at' })
  createdAt: Date;

  @UpdateDateColumn({ name: 'updated_at' })
  updatedAt: Date;
}

import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { json, urlencoded } from 'express';

async function bootstrap() {
  const app = await NestFactory.create(AppModule);
  app.use(json({ limit: '50mb' }));
  app.use(urlencoded({ limit: '50mb', extended: true }));
  app.enableCors();
  await app.listen(process.env.PORT ?? 3001);
}
bootstrap();

import {
  Controller,
  Post,
  Body,
  UseGuards,
  Request,
  ForbiddenException,
  BadRequestException,
  Param,
} from '@nestjs/common';
import { JwtAuthGuard } from '../auth/jwt-auth.guard';
import { MaintenanceService } from './maintenance.service';
import { Role } from '../auth/enums/role.enum';
import { Roles } from '../auth/decorators/roles.decorator';

@Controller('maintenance')
export class MaintenanceController {
  constructor(private readonly maintenanceService: MaintenanceService) {}

  @UseGuards(JwtAuthGuard)
  @Roles(Role.OWNER, Role.SUPER_ADMIN)
  @Post('reset-my-data')
  async resetMyData(@Request() req, @Body() options: any) {
    const { confirmText, ...resetOptions } = options;
    if (confirmText !== 'REINICIAR_TODO_A_CEROS') {
      throw new BadRequestException(
        'Confirmación inválida. Escriba exactamente: REINICIAR_TODO_A_CEROS',
      );
    }

    return this.maintenanceService.resetTenantData(
      req.user.tenantId,
      resetOptions,
    );
  }

  @UseGuards(JwtAuthGuard)
  @Roles(Role.SUPER_ADMIN)
  @Post('admin-reset/:tenantId')
  async adminResetTenant(
    @Request() req,
    @Body() options: any,
    @Param('tenantId') tenantId: string,
  ) {
    const { confirmText, ...resetOptions } = options;
    if (confirmText !== 'REINICIAR_SISTEMA_GLOBAL') {
      throw new BadRequestException(
        'Confirmación inválida para SuperAdmin. Escriba exactamente: REINICIAR_SISTEMA_GLOBAL',
      );
    }

    return this.maintenanceService.resetTenantData(tenantId, resetOptions);
  }
  @UseGuards(JwtAuthGuard)
  @Roles(Role.OWNER, Role.SUPER_ADMIN)
  @Post('cleanup-duplicates')
  async cleanupDuplicates() {
    return this.maintenanceService.cleanupDuplicateInvoices();
  }

  @UseGuards(JwtAuthGuard)
  @Roles(Role.SUPER_ADMIN)
  @Post('admin-cleanup-duplicates/:tenantId')
  async adminCleanupDuplicates(@Param('tenantId') tenantId: string) {
    return this.maintenanceService.cleanupDuplicateInvoices(tenantId);
  }
}

import { Injectable, ForbiddenException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, DataSource } from 'typeorm';
import { Sale } from '../sales/entities/sale.entity';
import { CreditSale } from '../sales/entities/credit-sale.entity';
import { CreditPayment } from '../sales/entities/credit-payment.entity';
import { CashClosure } from '../sales/entities/cash-closure.entity';
import { SupplierInvoice } from '../suppliers/entities/supplier-invoice.entity';
import { InvoiceItem } from '../suppliers/entities/invoice-item.entity';
import { SaleItem } from '../sales/entities/sale-item.entity';
import { Refund } from '../sales/entities/refund.entity';
import { RefundItem } from '../sales/entities/refund-item.entity';

@Injectable()
export class MaintenanceService {
  constructor(
    @InjectRepository(Sale)
    private salesRepo: Repository<Sale>,
    @InjectRepository(CreditSale)
    private creditSalesRepo: Repository<CreditSale>,
    @InjectRepository(CreditPayment)
    private creditPaymentsRepo: Repository<CreditPayment>,
    @InjectRepository(CashClosure)
    private cashClosuresRepo: Repository<CashClosure>,
    @InjectRepository(SupplierInvoice)
    private supplierInvoicesRepo: Repository<SupplierInvoice>,
    @InjectRepository(InvoiceItem)
    private invoiceItemsRepo: Repository<InvoiceItem>,
    @InjectRepository(SaleItem)
    private saleItemsRepo: Repository<SaleItem>,
    @InjectRepository(Refund)
    private refundRepo: Repository<Refund>,
    @InjectRepository(RefundItem)
    private refundItemRepo: Repository<RefundItem>,
    private dataSource: DataSource,
  ) {}

  async resetTenantData(
    tenantId: string,
    options: {
      cleanSales?: boolean;
      cleanCredits?: boolean;
      cleanCashClosures?: boolean;
      cleanRefunds?: boolean;
      cleanSupplierInvoices?: boolean;
    } = {},
  ) {
    return await this.dataSource.transaction(async (manager) => {
      const results = [];

      // 1. Credit Payments (Dependent on Credits)
      if (options.cleanCredits) {
        await manager.delete(CreditPayment, { tenantId });
        await manager.delete(CreditSale, { tenantId });
        results.push('Créditos y abonos');
      }

      // 2. Supplier Invoices and Items (Explicitly requested NOT to delete by default)
      if (options.cleanSupplierInvoices) {
        await manager.delete(InvoiceItem, { tenantId });
        await manager.delete(SupplierInvoice, { tenantId });
        results.push('Facturas de proveedores');
      }

      // 3. Refunds and Items
      if (options.cleanRefunds) {
        await manager.query(
          'DELETE FROM refund_items WHERE refund_id IN (SELECT id FROM refunds WHERE tenant_id = $1)',
          [tenantId],
        );
        await manager.delete(Refund, { tenantId });
        results.push('Devoluciones');
      }

      // 4. Sales and Items
      if (options.cleanSales) {
        await manager.query(
          'DELETE FROM sale_items WHERE sale_id IN (SELECT id FROM sales WHERE tenant_id = $1)',
          [tenantId],
        );
        await manager.delete(Sale, { tenantId });
        results.push('Ventas y facturas de venta');
      }

      // 5. Cash Closures
      if (options.cleanCashClosures) {
        await manager.delete(CashClosure, { tenantId });
        results.push('Cierres de caja');
      }

      const message =
        results.length > 0
          ? `Se han reiniciado los siguientes datos: ${results.join(', ')}.`
          : 'No se seleccionaron datos para reiniciar.';

      return { success: true, message };
    });
  }

  async cleanupDuplicateInvoices(tenantId?: string) {
    return await this.dataSource.transaction(async (manager) => {
      // Build the WHERE clause
      let whereClause = 'WHERE invoice_number IS NOT NULL';
      const params = [];
      if (tenantId) {
        whereClause += ' AND tenant_id = $1';
        params.push(tenantId);
      }

      // Find and delete sales keeping only the newest one for each (tenant_id, invoice_number)
      const result = await manager.query(
        `
        DELETE FROM sales
        WHERE id IN (
          SELECT id FROM (
            SELECT id, ROW_NUMBER() OVER (
              PARTITION BY tenant_id, invoice_number 
              ORDER BY created_at DESC, id DESC
            ) as row_num
            FROM sales
            ${whereClause}
          ) sub
          WHERE row_num > 1
        )
      `,
        params,
      );

      return {
        success: true,
        message:
          'Limpieza de facturas duplicadas completada. Ahora es seguro activar la restricción de integridad.',
      };
    });
  }
}

